     5→//! Query operations for Gallops JSON
     6→//!
     7→//! Implements read operations: muster, saddle, parade, retire.
     8→//! All operations read from Gallops JSON and optionally paddock files.
     9→
    10→use crate::jjrf_favor::jjrf_Firemark as Firemark;
    11→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState};
    12→use serde::Serialize;
    13→use std::fs;
    14→
    15→// ============================================================================
    16→// Muster - List all Heats with summary information
    17→// ============================================================================
    18→
    19→/// Arguments for muster command
    20→#[derive(Debug)]
    21→pub struct jjrq_MusterArgs {
    22→    pub file: std::path::PathBuf,
    23→    pub status: Option<HeatStatus>,
    24→}
    25→
    26→/// Run the muster command - list Heats as TSV
    27→pub fn jjrq_run_muster(args: jjrq_MusterArgs) -> i32 {
    28→    let gallops = match Gallops::jjrg_load(&args.file) {
    29→        Ok(g) => g,
    30→        Err(e) => {
    31→            eprintln!("jjx_muster: error: {}", e);
    32→            return 1;
    33→        }
    34→    };
    35→
    36→    for (key, heat) in &gallops.heats {
    37→        // Apply status filter if provided
    38→        if let Some(ref filter_status) = args.status {
    39→            if &heat.status != filter_status {
    40→                continue;
    41→            }
    42→        }
    43→
    44→        let pace_count = heat.paces.len();
    45→        let status_str = match heat.status {
    46→            HeatStatus::Current => "current",
    47→            HeatStatus::Retired => "retired",
    48→        };
    49→
    50→        println!("{}\t{}\t{}\t{}", key, heat.silks, status_str, pace_count);
    51→    }
    52→
    53→    0
    54→}
    55→
    56→// ============================================================================
    57→// Saddle - Return context needed to saddle up on a Heat
    58→// ============================================================================
    59→
    60→/// Arguments for saddle command
    61→#[derive(Debug)]
    62→pub struct jjrq_SaddleArgs {
    63→    pub file: std::path::PathBuf,
    64→    pub firemark: Firemark,
    65→}
    66→
    67→/// Output structure for saddle command
    68→#[derive(Serialize)]
    69→struct zjjrq_SaddleOutput {
    70→    heat_silks: String,
    71→    paddock_file: String,
    72→    paddock_content: String,
    73→    #[serde(skip_serializing_if = "Option::is_none")]
    74→    pace_coronet: Option<String>,
    75→    #[serde(skip_serializing_if = "Option::is_none")]
    76→    pace_silks: Option<String>,
    77→    #[serde(skip_serializing_if = "Option::is_none")]
    78→    pace_state: Option<String>,
    79→    #[serde(skip_serializing_if = "Option::is_none")]
    80→    spec: Option<String>,
    81→    #[serde(skip_serializing_if = "Option::is_none")]
    82→    direction: Option<String>,
    83→}
    84→
    85→/// Run the saddle command - return Heat context
    86→pub fn jjrq_run_saddle(args: jjrq_SaddleArgs) -> i32 {
    87→    let gallops = match Gallops::jjrg_load(&args.file) {
    88→        Ok(g) => g,
    89→        Err(e) => {
    90→            eprintln!("jjx_saddle: error: {}", e);
    91→            return 1;
    92→        }
    93→    };
    94→
    95→    let heat_key = args.firemark.jjrf_display();
    96→    let heat = match gallops.heats.get(&heat_key) {
    97→        Some(h) => h,
    98→        None => {
    99→            eprintln!("jjx_saddle: error: Heat '{}' not found", heat_key);
   100→            return 1;
   101→        }
   102→    };
   103→
   104→    // Read paddock file content
   105→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   106→        Ok(content) => content,
   107→        Err(e) => {
   108→            eprintln!("jjx_saddle: error reading paddock file '{}': {}", heat.paddock_file, e);
   109→            return 1;
   110→        }
   111→    };
   112→
   113→    // Find first actionable pace (rough or primed)
   114→    let mut output = zjjrq_SaddleOutput {
   115→        heat_silks: heat.silks.clone(),
   116→        paddock_file: heat.paddock_file.clone(),
   117→        paddock_content,
   118→        pace_coronet: None,
   119→        pace_silks: None,
   120→        pace_state: None,
   121→        spec: None,
   122→        direction: None,
   123→    };
   124→
   125→    for coronet_key in &heat.order {
   126→        if let Some(pace) = heat.paces.get(coronet_key) {
   127→            if let Some(tack) = pace.tacks.first() {
   128→                match tack.state {
   129→                    PaceState::Rough | PaceState::Primed => {
   130→                        output.pace_coronet = Some(coronet_key.clone());
   131→                        output.pace_silks = Some(pace.silks.clone());
   132→                        output.pace_state = Some(match tack.state {
   133→                            PaceState::Rough => "rough".to_string(),
   134→                            PaceState::Primed => "primed".to_string(),
   135→                            _ => unreachable!(),
   136→                        });
   137→                        output.spec = Some(tack.text.clone());
   138→                        if tack.state == PaceState::Primed {
   139→                            output.direction = tack.direction.clone();
   140→                        }
   141→                        break;
   142→                    }
   143→                    _ => continue,
   144→                }
   145→            }
   146→        }
   147→    }
   148→
   149→    // Output JSON
   150→    match serde_json::to_string_pretty(&output) {
   151→        Ok(json) => {
   152→            println!("{}", json);
   153→            0
   154→        }
   155→        Err(e) => {
   156→            eprintln!("jjx_saddle: error serializing output: {}", e);
   157→            1
   158→        }
   159→    }
   160→}
   161→
   162→// ============================================================================
   163→// Parade - Display comprehensive Heat status for project review
   164→// ============================================================================
   165→
   166→/// Output format modes for parade command
   167→#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
   168→pub enum jjrq_ParadeFormat {
   169→    /// One line per pace: [state] silks (₢coronet)
   170→    Overview,
   171→    /// Numbered list: N. [state] silks (₢coronet)
   172→    Order,
   173→    /// Full tack text for one pace (requires --pace)
   174→    Detail,
   175→    /// Paddock + all paces with tack text (default)
   176→    #[default]
   177→    Full,
   178→}
   179→
   180→/// Arguments for parade command
   181→#[derive(Debug)]
   182→pub struct jjrq_ParadeArgs {
   183→    pub file: std::path::PathBuf,
   184→    pub firemark: Firemark,
   185→    pub format: jjrq_ParadeFormat,
   186→    pub pace: Option<String>,
   187→    pub remaining: bool,
   188→}
   189→
   190→/// Run the parade command - display comprehensive Heat status
   191→pub fn jjrq_run_parade(args: jjrq_ParadeArgs) -> i32 {
   192→    // Validate: detail format requires --pace
   193→    if args.format == jjrq_ParadeFormat::Detail && args.pace.is_none() {
   194→        eprintln!("jjx_parade: error: --format detail requires --pace <coronet>");
   195→        return 1;
   196→    }
   197→
   198→    let gallops = match Gallops::jjrg_load(&args.file) {
   199→        Ok(g) => g,
   200→        Err(e) => {
   201→            eprintln!("jjx_parade: error: {}", e);
   202→            return 1;
   203→        }
   204→    };
   205→
   206→    let heat_key = args.firemark.jjrf_display();
   207→    let heat = match gallops.heats.get(&heat_key) {
   208→        Some(h) => h,
   209→        None => {
   210→            eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   211→            return 1;
   212→        }
   213→    };
   214→
   215→    match args.format {
   216→        jjrq_ParadeFormat::Overview => {
   217→            for coronet_key in &heat.order {
   218→                if let Some(pace) = heat.paces.get(coronet_key) {
   219→                    if let Some(tack) = pace.tacks.first() {
   220→                        // Skip complete/abandoned if --remaining
   221→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   222→                            continue;
   223→                        }
   224→                        let state_str = zjjrq_pace_state_str(&tack.state);
   225→                        println!("[{}] {} ({})", state_str, pace.silks, coronet_key);
   226→                    }
   227→                }
   228→            }
   229→        }
   230→        jjrq_ParadeFormat::Order => {
   231→            let mut num = 0;
   232→            for coronet_key in &heat.order {
   233→                if let Some(pace) = heat.paces.get(coronet_key) {
   234→                    if let Some(tack) = pace.tacks.first() {
   235→                        // Skip complete/abandoned if --remaining
   236→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   237→                            continue;
   238→                        }
   239→                        num += 1;
   240→                        let state_str = zjjrq_pace_state_str(&tack.state);
   241→                        println!("{}. [{}] {} ({})", num, state_str, pace.silks, coronet_key);
   242→                    }
   243→                }
   244→            }
   245→        }
   246→        jjrq_ParadeFormat::Detail => {
   247→            let target_coronet = args.pace.as_ref().unwrap();
   248→            let pace = match heat.paces.get(target_coronet) {
   249→                Some(p) => p,
   250→                None => {
   251→                    eprintln!("jjx_parade: error: Pace '{}' not found in Heat '{}'", target_coronet, heat_key);
   252→                    return 1;
   253→                }
   254→            };
   255→            if let Some(tack) = pace.tacks.first() {
   256→                let state_str = zjjrq_pace_state_str(&tack.state);
   257→                println!("Pace: {} ({})", pace.silks, target_coronet);
   258→                println!("State: {}", state_str);
   259→                println!("Heat: {}", heat_key);
   260→                println!();
   261→                println!("{}", tack.text);
   262→                if let Some(ref direction) = tack.direction {
   263→                    println!();
   264→                    println!("Direction: {}", direction);
   265→                }
   266→            }
   267→        }
   268→        jjrq_ParadeFormat::Full => {
   269→            // Read paddock file content
   270→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   271→                Ok(content) => content,
   272→                Err(e) => {
   273→                    eprintln!("jjx_parade: error reading paddock file '{}': {}", heat.paddock_file, e);
   274→                    return 1;
   275→                }
   276→            };
   277→
   278→            let status_str = match heat.status {
   279→                HeatStatus::Current => "current",
   280→                HeatStatus::Retired => "retired",
   281→            };
   282→
   283→            println!("Heat: {} ({})", heat.silks, heat_key);
   284→            println!("Status: {}", status_str);
   285→            println!("Created: {}", heat.creation_time);
   286→            println!();
   287→            println!("## Paddock");
   288→            println!();
   289→            println!("{}", paddock_content);
   290→            println!();
   291→            println!("## Paces");
   292→            println!();
   293→
   294→            for coronet_key in &heat.order {
   295→                if let Some(pace) = heat.paces.get(coronet_key) {
   296→                    if let Some(tack) = pace.tacks.first() {
   297→                        // Skip complete/abandoned if --remaining
   298→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   299→                            continue;
   300→                        }
   301→                        let state_str = zjjrq_pace_state_str(&tack.state);
   302→                        println!("### {} ({}) [{}]", pace.silks, coronet_key, state_str);
   303→                        println!();
   304→                        println!("{}", tack.text);
   305→                        if let Some(ref direction) = tack.direction {
   306→                            println!();
   307→                            println!("**Direction:** {}", direction);
   308→                        }
   309→                        println!();
   310→                    }
   311→                }
   312→            }
   313→        }
   314→    }
   315→
   316→    0
   317→}
   318→
   319→/// Helper to convert PaceState to display string
   320→fn zjjrq_pace_state_str(state: &PaceState) -> &'static str {
   321→    match state {
   322→        PaceState::Rough => "rough",
   323→        PaceState::Primed => "primed",
   324→        PaceState::Complete => "complete",
   325→        PaceState::Abandoned => "abandoned",
   326→    }
   327→}
   328→
   329→// ============================================================================
   330→// Retire - Extract complete Heat data for archival trophy
   331→// ============================================================================
   332→
   333→/// Arguments for retire command
   334→#[derive(Debug)]
   335→pub struct jjrq_RetireArgs {
   336→    pub file: std::path::PathBuf,
   337→    pub firemark: Firemark,
   338→}
   339→
   340→/// Output structure for retire command
   341→#[derive(Serialize)]
   342→struct zjjrq_RetireOutput {
   343→    firemark: String,
   344→    silks: String,
   345→    created: String,
   346→    status: String,
   347→    paddock_file: String,
   348→    paddock_content: String,
   349→    paces: Vec<zjjrq_RetirePace>,
   350→    // TODO: steeplechase array from jjx_rein
   351→    // steeplechase: Vec<SteeplechaseEntry>,
   352→}
   353→
   354→/// Pace structure for retire output (full tack history)
   355→#[derive(Serialize)]
   356→struct zjjrq_RetirePace {
   357→    coronet: String,
   358→    silks: String,
   359→    tacks: Vec<zjjrq_RetireTack>,
   360→}
   361→
   362→/// Tack structure for retire output
   363→#[derive(Serialize)]
   364→struct zjjrq_RetireTack {
   365→    ts: String,
   366→    state: String,
   367→    text: String,
   368→    #[serde(skip_serializing_if = "Option::is_none")]
   369→    direction: Option<String>,
   370→}
   371→
   372→/// Run the retire command - extract complete Heat data for archival
   373→pub fn jjrq_run_retire(args: jjrq_RetireArgs) -> i32 {
   374→    let gallops = match Gallops::jjrg_load(&args.file) {
   375→        Ok(g) => g,
   376→        Err(e) => {
   377→            eprintln!("jjx_retire: error: {}", e);
   378→            return 1;
   379→        }
   380→    };
   381→
   382→    let heat_key = args.firemark.jjrf_display();
   383→    let heat = match gallops.heats.get(&heat_key) {
   384→        Some(h) => h,
   385→        None => {
   386→            eprintln!("jjx_retire: error: Heat '{}' not found", heat_key);
   387→            return 1;
   388→        }
   389→    };
   390→
   391→    // Read paddock file content
   392→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   393→        Ok(content) => content,
   394→        Err(e) => {
   395→            eprintln!("jjx_retire: error reading paddock file '{}': {}", heat.paddock_file, e);
   396→            return 1;
   397→        }
   398→    };
   399→
   400→    // Build paces array with full tack history, ordered per Heat's order array
   401→    let mut paces = Vec::new();
   402→    for coronet_key in &heat.order {
   403→        if let Some(pace) = heat.paces.get(coronet_key) {
   404→            let tacks: Vec<zjjrq_RetireTack> = pace.tacks.iter().map(|tack| {
   405→                zjjrq_RetireTack {
   406→                    ts: tack.ts.clone(),
   407→                    state: match tack.state {
   408→                        PaceState::Rough => "rough".to_string(),
   409→                        PaceState::Primed => "primed".to_string(),
   410→                        PaceState::Complete => "complete".to_string(),
   411→                        PaceState::Abandoned => "abandoned".to_string(),
   412→                    },
   413→                    text: tack.text.clone(),
   414→                    direction: tack.direction.clone(),
   415→                }
   416→            }).collect();
   417→
   418→            paces.push(zjjrq_RetirePace {
   419→                coronet: coronet_key.clone(),
   420→                silks: pace.silks.clone(),
   421→                tacks,
   422→            });
   423→        }
   424→    }
   425→
   426→    let output = zjjrq_RetireOutput {
   427→        firemark: heat_key.clone(),
   428→        silks: heat.silks.clone(),
   429→        created: heat.creation_time.clone(),
   430→        status: match heat.status {
   431→            HeatStatus::Current => "current".to_string(),
   432→            HeatStatus::Retired => "retired".to_string(),
   433→        },
   434→        paddock_file: heat.paddock_file.clone(),
   435→        paddock_content,
   436→        paces,
   437→        // TODO: Call jjx_rein internally to get steeplechase entries
   438→    };
   439→
   440→    // Output JSON
   441→    match serde_json::to_string_pretty(&output) {
   442→        Ok(json) => {
   443→            println!("{}", json);
   444→            0
   445→        }
   446→        Err(e) => {
   447→            eprintln!("jjx_retire: error serializing output: {}", e);
   448→            1
   449→        }
   450→    }
   451→}
