   463→    fn create_test_gallops() -> Gallops {
   464→        let mut paces = BTreeMap::new();
   465→        paces.insert(
   466→            "₢ABAAA".to_string(),
   467→            Pace {
   468→                silks: "test-pace-one".to_string(),
   469→                tacks: vec![Tack {
   470→                    ts: "260101-1200".to_string(),
   471→                    state: PaceState::Rough,
   472→                    text: "First pace rough plan".to_string(),
   473→                    direction: None,
   474→                }],
   475→            },
   476→        );
   477→        paces.insert(
   478→            "₢ABAAB".to_string(),
   479→            Pace {
   480→                silks: "test-pace-two".to_string(),
   481→                tacks: vec![Tack {
   482→                    ts: "260101-1300".to_string(),
   483→                    state: PaceState::Complete,
   484→                    text: "Completed pace".to_string(),
   485→                    direction: None,
   486→                }],
   487→            },
   488→        );
   489→
   490→        let mut heats = BTreeMap::new();
   491→        heats.insert(
   492→            "₣AB".to_string(),
   493→            Heat {
   494→                silks: "test-heat".to_string(),
   495→                creation_time: "260101".to_string(),
   496→                status: HeatStatus::Current,
   497→                order: vec!["₢ABAAA".to_string(), "₢ABAAB".to_string()],
   498→                next_pace_seed: "AAC".to_string(),
   499→                paddock_file: ".claude/jjm/jjp_AB.md".to_string(),
   500→                paces,
   501→            },
   502→        );
   503→
   504→        Gallops {
   505→            next_heat_seed: "AC".to_string(),
