   507→        }
   508→    }
   509→
   510→    #[test]
   511→    fn test_muster_output_format() {
   512→        // This test validates the TSV format conceptually
   513→        // Full integration test would need file I/O
   514→        let gallops = create_test_gallops();
   515→        let heat = gallops.heats.get("₣AB").unwrap();
   516→        let expected_format = format!(
