   561→    #[test]
   562→    fn test_saddle_output_no_actionable_pace() {
   563→        let output = zjjrq_SaddleOutput {
   564→            heat_silks: "my-heat".to_string(),
   565→            paddock_file: ".claude/jjm/jjp_AB.md".to_string(),
   566→            paddock_content: "# All done".to_string(),
   567→            pace_coronet: None,
   568→            pace_silks: None,
   569→            pace_state: None,
   570→            spec: None,
   571→            direction: None,
