   578→
   579→    #[test]
   580→    fn test_parade_format_enum() {
   581→        // Test ParadeFormat default
   582→        let format: jjrq_ParadeFormat = Default::default();
   583→        assert_eq!(format, jjrq_ParadeFormat::Full);
   584→    }
   585→
   586→    #[test]
   587→    fn test_retire_output_structure() {
   588→        let output = zjjrq_RetireOutput {
